package org.example.controller;
import jakarta.validation.Valid; import org.example.model.dto.*; import org.example.security.JwtService; import org.example.service.AuthService; import org.springframework.security.authentication.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/auth") public class AuthController { private final AuthService authService; private final AuthenticationManager authenticationManager; private final JwtService jwtService; public AuthController(AuthService a, AuthenticationManager am, JwtService j){this.authService=a;this.authenticationManager=am;this.jwtService=j;} @PostMapping("/register") public String register(@RequestBody @Valid RegisterRequest r){authService.registerUser(r); return "Пользователь успешно зарегистрирован";} @PostMapping("/register-admin") public String registerAdmin(@RequestBody @Valid RegisterRequest r){authService.registerAdmin(r); return "Администратор успешно зарегистрирован";} @PostMapping("/login") public AuthResponse login(@RequestBody @Valid LoginRequest r){authenticationManager.authenticate(new UsernamePasswordAuthenticationToken(r.getEmail(), r.getPassword())); return new AuthResponse(jwtService.generateToken(r.getEmail()));} @PostMapping("/login-raw") public String loginRaw(@RequestBody @Valid LoginRequest r){authenticationManager.authenticate(new UsernamePasswordAuthenticationToken(r.getEmail(), r.getPassword())); return jwtService.generateToken(r.getEmail());} }
